# Create S3 bucket with Object Lock for immutable logs
resource "aws_s3_bucket" "immutable_logs" {
  bucket = "company-siem-logs-immutable-${var.account_id}"

  # CRITICAL: Object Lock must be enabled at bucket creation
  object_lock_enabled = true

  tags = {
    Purpose     = "Immutable SIEM Logs"
    Compliance  = "SOC2-ISO27001"
    Retention   = "7-years"
  }
}

# Enable versioning (required for Object Lock)
resource "aws_s3_bucket_versioning" "immutable_logs" {
  bucket = aws_s3_bucket.immutable_logs.id

  versioning_configuration {
    status = "Enabled"
  }
}

# Configure Object Lock in Compliance Mode (cannot be deleted even by root)
resource "aws_s3_bucket_object_lock_configuration" "immutable_logs" {
  bucket = aws_s3_bucket.immutable_logs.id

  rule {
    default_retention {
      mode = "COMPLIANCE"  # GOVERNANCE allows privileged users to bypass
      days = 2555          # 7 years retention
    }
  }
}

# Block all public access
resource "aws_s3_bucket_public_access_block" "immutable_logs" {
  bucket = aws_s3_bucket.immutable_logs.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Enforce encryption at rest
resource "aws_s3_bucket_server_side_encryption_configuration" "immutable_logs" {
  bucket = aws_s3_bucket.immutable_logs.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.log_encryption.arn
    }
    bucket_key_enabled = true
  }
}

# CloudTrail configuration to send logs to immutable S3
resource "aws_cloudtrail" "main" {
  name                          = "organization-trail"
  s3_bucket_name                = aws_s3_bucket.immutable_logs.id
  include_global_service_events = true
  is_multi_region_trail         = true
  enable_log_file_validation    = true  # Cryptographic log integrity

  event_selector {
    read_write_type           = "All"
    include_management_events = true

    data_resource {
      type   = "AWS::S3::Object"
      values = ["arn:aws:s3:::*/*"]
    }
  }
}

# CloudWatch Logs to S3 export (Lambda-based)
resource "aws_iam_role" "cloudwatch_to_s3" {
  name = "cloudwatch-logs-to-s3-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy" "cloudwatch_to_s3" {
  role = aws_iam_role.cloudwatch_to_s3.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateExportTask",
          "logs:DescribeExportTasks"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:PutObjectRetention"  # Set retention at upload
        ]
        Resource = "${aws_s3_bucket.immutable_logs.arn}/*"
      }
    ]
  })
}

# Example: Prevent log deletion via SCP (AWS Organizations)
# Apply to all accounts in the organization
resource "aws_organizations_policy" "prevent_log_deletion" {
  name        = "PreventLogDeletion"
  description = "Deny deletion of CloudTrail trails and CloudWatch log groups"
  type        = "SERVICE_CONTROL_POLICY"

  content = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "DenyCloudTrailDeletion"
        Effect = "Deny"
        Action = [
          "cloudtrail:DeleteTrail",
          "cloudtrail:StopLogging",
          "cloudtrail:UpdateTrail"
        ]
        Resource = "*"
        Condition = {
          StringNotEquals = {
            "aws:PrincipalOrgID" = var.security_account_id
          }
        }
      },
      {
        Sid    = "DenyLogGroupDeletion"
        Effect = "Deny"
        Action = [
          "logs:DeleteLogGroup",
          "logs:DeleteLogStream"
        ]
        Resource = "*"
      }
    ]
  })
}

# Create Azure Storage Account with versioning and immutability
resource "azurerm_storage_account" "immutable_logs" {
  name                     = "companylogssiem${var.environment}"
  resource_group_name      = azurerm_resource_group.security.name
  location                 = azurerm_resource_group.security.location
  account_tier             = "Standard"
  account_replication_type = "GRS"  # Geo-redundant
  account_kind             = "StorageV2"

  blob_properties {
    versioning_enabled = true
    change_feed_enabled = true  # Track all blob changes

    delete_retention_policy {
      days = 365  # Soft delete protection
    }

    container_delete_retention_policy {
      days = 365
    }
  }

  tags = {
    Purpose    = "Immutable SIEM Logs"
    Compliance = "HIPAA-SOC2-ISO27001"
  }
}

# Create container with immutability policy
resource "azurerm_storage_container" "audit_logs" {
  name                  = "audit-logs"
  storage_account_name  = azurerm_storage_account.immutable_logs.name
  container_access_type = "private"
}

# Apply time-based immutability policy (WORM)
resource "azurerm_storage_management_policy" "immutability" {
  storage_account_id = azurerm_storage_account.immutable_logs.id

  rule {
    name    = "immutable-retention"
    enabled = true

    filters {
      prefix_match = ["audit-logs/"]
      blob_types   = ["blockBlob"]
    }

    actions {
      version {
        delete_after_days_since_creation = 2555  # 7 years
      }
    }
  }
}

# Configure Azure Monitor Diagnostic Settings to send logs to immutable storage
resource "azurerm_monitor_diagnostic_setting" "activity_logs" {
  name                       = "activity-logs-to-immutable-storage"
  target_resource_id         = data.azurerm_subscription.current.id
  storage_account_id         = azurerm_storage_account.immutable_logs.id

  enabled_log {
    category = "Administrative"
  }

  enabled_log {
    category = "Security"
  }

  enabled_log {
    category = "ServiceHealth"
  }

  enabled_log {
    category = "Alert"
  }

  metric {
    category = "AllMetrics"
  }
}

# Azure Policy to enforce immutability on all storage accounts
resource "azurerm_policy_definition" "enforce_immutable_logs" {
  name         = "enforce-immutable-logging"
  policy_type  = "Custom"
  mode         = "All"
  display_name = "Enforce immutability on audit log storage accounts"

  policy_rule = jsonencode({
    if = {
      allOf = [
        {
          field = "type"
          equals = "Microsoft.Storage/storageAccounts"
        },
        {
          field = "tags['Purpose']"
          equals = "Immutable SIEM Logs"
        }
      ]
    }
    then = {
      effect = "audit"
      details = {
        type = "Microsoft.Storage/storageAccounts/blobServices"
        existenceCondition = {
          field = "Microsoft.Storage/storageAccounts/blobServices/containers/immutabilityPolicy.properties.state"
          equals = "Locked"
        }
      }
    }
  })
}

# Lock immutability policy (cannot be removed once locked)
resource "null_resource" "lock_immutability_policy" {
  depends_on = [azurerm_storage_container.audit_logs]

  provisioner "local-exec" {
    command = <<-EOT
      az storage container immutability-policy create \
        --account-name ${azurerm_storage_account.immutable_logs.name} \
        --container-name ${azurerm_storage_container.audit_logs.name} \
        --period 2555 \
        --resource-group ${azurerm_resource_group.security.name}

      # Lock the policy (IRREVERSIBLE)
      az storage container immutability-policy lock \
        --account-name ${azurerm_storage_account.immutable_logs.name} \
        --container-name ${azurerm_storage_container.audit_logs.name} \
        --if-match $(az storage container immutability-policy show \
          --account-name ${azurerm_storage_account.immutable_logs.name} \
          --container-name ${azurerm_storage_container.audit_logs.name} \
          --query etag -o tsv) \
        --resource-group ${azurerm_resource_group.security.name}
    EOT
  }
}
